    ('CHEM-C 372', 'CHEMISTRY WITH MOLECULAR MODELING', '33642', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'TV 250', 'Philip Shushkov', 15, NULL, 'Lecture', '3', 'RADIO-TV', ARRAY[]::TEXT[], 'Focuses on computational prediction of the structure and properties of a single molecule or a series of a few related molecules. Molecular properties covered include molecular geometries; electronic distribution and molecular orbitals; molecular energetics and thermochemistry; molecular spectra such as IR and UV-Vis spectra; and intermolecular interactions.', ARRAY[]::TEXT[], NULL),
