    ('CHEM-C 427', 'ADVANCED AND NANOSCALE MATERIALS LABORATORY', '10506', 'Class Status', 'Tu Tuesday 11:35 AM–12:25 PM', 'CH 001', 'Xingchen Ye', 7, 'Lecture', 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'This is a junior-senior level overview of advanced and nanoscale materials including hard, soft and hybrid materials with a focus on structure-function relationships. Lab techniques include materials synthesis, structural characterization, modeling of structures, and spectroscopic characterization. Emphasis is on modern research methods.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 427', 'ADVANCED AND NANOSCALE MATERIALS LABORATORY', '10507', 'Class Status', 'Th Thursday 9:00 AM–1:00 PM', 'CH 141', 'Staff', 8, 'Laboratory', 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'This is a junior-senior level overview of advanced and nanoscale materials including hard, soft and hybrid materials with a focus on structure-function relationships. Lab techniques include materials synthesis, structural characterization, modeling of structures, and spectroscopic characterization. Emphasis is on modern research methods.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 427', 'ADVANCED AND NANOSCALE MATERIALS LABORATORY', '12003', 'Closed', 'Th Thursday 1:20 PM–5:20 PM', 'CH 141', 'Staff', 0, 'Laboratory', 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'This is a junior-senior level overview of advanced and nanoscale materials including hard, soft and hybrid materials with a focus on structure-function relationships. Lab techniques include materials synthesis, structural characterization, modeling of structures, and spectroscopic characterization. Emphasis is on modern research methods.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 432', 'SPECTROSCOPIC METHODS IN INORGANIC CHEMISTRY', '12364', 'Class Status', 'MTh Monday, Thursday 6:00 PM–7:30 PM', 'CH 127 CH 127', 'Jeffrey Zaleski', 8, NULL, 'Lecture', '3', 'CHEMISTRY', ARRAY[]::TEXT[], 'Chemical applications of group theory and the elucidation of structure and bonding in inorganic molecules and complexes by vibrational, nuclear magnetic resonance, Mössbauer, and electronic absorption spectroscopy.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 443', 'ORGANIC SPECTROSCOPY', '6435', 'Class Status', NULL, 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM W Wednesday 7:15 PM–9:15 PM W Wednesday 7:15 PM–9:15 PM W Wednesday 7:15 PM–9:15 PM Regular Academic Session 8/25/2025–12/19/2025', 'BH 310 HD TBA HD TBA HD TBA', NULL, NULL, 'Lecture', '3', 'BALLANTINE HALL, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Elucidation of molecular structures, by use of IR, UV, NMR, mass spectroscopy, and other methods.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 450', 'ADVANCED ORGANIC CHEMISTRY', '11353', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'CX A400', 'Nicola Pohl', 5, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Covers valence and molecule structure, electronic interpretation of organic reactions, and stereochemistry. Includes discussion of myriad chemical reaction mechanisms and focuses on physical methods utilized to experimentally define reaction mechanisms.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 453', 'INTRODUCTION TO CHEMICAL BIOLOGY I', '11354', 'Class Status', 'MWF Monday, Wednesday, Friday 11:10 AM–12:25 PM', 'CX A500', 'Youngchan Park', 4, NULL, 'Lecture', '1.5', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Introduces key concepts in chemical biology. At the interface of biochemistry and chemistry, biochemical reactions and their synthetic counterparts are presented in the context of application to better understand biological systems, to develop chemical probes, or to guide drug design.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 454', 'INTRODUCTION TO CHEMICAL BIOLOGY II', '11355', 'Class Status', 'MWF Monday, Wednesday, Friday 11:10 AM–12:25 PM', 'CX A500', 'Youngchan Park', 5, NULL, 'Lecture', '1.5', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Introduces key concepts in chemical biology. Moving the focus beyond proteins, biochemical processes involving nucleic acid (DNA and RNA) and glycans (sugars) are presented in the context of the use of chemical probes to biological systems or the mechanism of drug action.', ARRAY[]::TEXT[], NULL),
