    ('CHEM-C 501', 'CHEMICAL INSTRUMENTATION', '7860', 'Class Status', 'TuTh Tuesday, Thursday 10:25 AM–11:15 AM', 'CH 127', 'Stephen Jacobson', 5, 'Lecture', 'Lecture', '4', 'CHEMISTRY', ARRAY[]::TEXT[], 'Electronics as applied to chemical instrumentation; design and construction of instruments used in chemical research, analysis, recording, and control; maintenance and practice in modification to meet special needs.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 501', 'CHEMICAL INSTRUMENTATION', '13016', 'Class Status', 'W Wednesday 12:45 PM–4:30 PM', 'CH 208', 'Staff', 5, 'Laboratory', 'Lecture', '4', 'CHEMISTRY', ARRAY[]::TEXT[], 'Electronics as applied to chemical instrumentation; design and construction of instruments used in chemical research, analysis, recording, and control; maintenance and practice in modification to meet special needs.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 501', 'CHEMICAL INSTRUMENTATION', '9288', 'Closed', 'Th Thursday 12:45 PM–4:30 PM', 'CH 208', 'Staff', 0, 'Laboratory', 'Lecture', '4', 'CHEMISTRY', ARRAY[]::TEXT[], 'Electronics as applied to chemical instrumentation; design and construction of instruments used in chemical research, analysis, recording, and control; maintenance and practice in modification to meet special needs.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 502', 'INORGANIC SPECTROSCOPY', '12365', 'Class Status', 'MTh Monday, Thursday 6:00 PM–7:30 PM', 'CH 127 CH 127', 'Jeffrey Zaleski', 24, NULL, 'Lecture', '3', 'CHEMISTRY', ARRAY[]::TEXT[], 'Chemical applications of group theory, and the elucidation of structure and bonding in inorganic molecules and complexes by vibrational, clear magnetic resonance. Mossbauer and electronic absorption spectroscopy.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 503', 'SPECTROMETRIC METHODS OF STRUCTURE DETERMINATION', '6438', 'Class Status', NULL, 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM W Wednesday 7:15 PM–9:15 PM W Wednesday 7:15 PM–9:15 PM W Wednesday 7:15 PM–9:15 PM Regular Academic Session 8/25/2025–12/19/2025', 'BH 310 HD TBA HD TBA HD TBA', NULL, NULL, 'Lecture', '3', 'BALLANTINE HALL, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'The elucidation of molecular structure utilizing ir, uv and nmr spectroscopy, mass spectrometry and other methods.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 505', 'GRADUATE PROFESSIONAL DEVELOPMENT SEMINAR', '9255', 'Class Status', NULL, 'Th Thursday 8:00 AM–9:15 AM Tu Tuesday 5:00 PM–6:30 PM Tu Tuesday 5:00 PM–6:30 PM Regular Academic Session 8/25/2025–12/19/2025', 'CH 001 JH 124 JH 124', NULL, NULL, 'Seminar', '1', 'CHEMISTRY, BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Incoming graduate students will be exposed to three core areas: teaching skills, research skills and professional skills. Topics include classroom management for discussion/labs, grading, effective research habits and time management, CVs, ethics, library skills, grant writing, and making the most out of your PhD.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 540', 'ADVANCED ORGANIC CHEMISTRY', '1306', 'Class Status', 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM', 'CX A400', 'Nicola Pohl', 58, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Valence and molecular structure, electronic interpretation of organic reactions, stereochemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 543', 'ORGANIC REACTIONS', '1307', 'Class Status', 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM', 'CX A400', 'Thomas Snaddon', 6, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CHEM-C 561', 'ATOMIC AND MOLECULAR QUANTUM THEORY', '1308', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 217', 'Philip Shushkov', 15, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Elements of quantum theory, solution of elementary problems with chemical applications, approximate methods, atomic structure, molecular symmetry and normal vibrations, the molecular orbital description of molecules.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 567', 'CHEMICAL STATISTICAL MECHANICS', '14136', 'Class Status', 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM', 'CX A300', 'Bogdan Dragnea', 11, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Introduction to equilibrium and no equilibrium many-body systems suing ensemble techniques. Emphasis on molecular systems and systems undergoing chemical transformation or transport. Both qualitative and rigorous approaches.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 581', 'MACROMOLECULAR STRUCTURE AND FUNCTION', '10510', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SI 001', 'Marc Morais', 12, NULL, 'Lecture', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Molecular Biology and Physical Chemistry Review; Recombinant DNA Techniques; Heterologous Protein Expression Systems; Description and Measurement of Stabilizing Forces in Macromolecular Structure; Protein Secondary, Tertiary and Quaternary Structures: Circular Dichroism and Analytical Ultracentrifugation; Nucleic and Structure and Probing; Protein Structure Determination by Nuclear Magnetic Resonance (NMR); Protein Structure Determination by X-ray Crystallography; Building and Refinement of a Protein Structure from Crystallographic Data', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 582', 'BIOMOLECULAR ANALYSIS AND INTERACTION', '5578', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'SI 001', 'Adam Zlotnick', 14, NULL, 'Lecture', '1.5', 'SIMON HALL (SCIENCE)', ARRAY[]::TEXT[], 'Ligand Binding Models: Single Site Binding and Multiple and Competitive Site Binding; and Determination and Measurement of Binding Interactions and Antibody-based Interaction Methods.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 612', 'SPECTROCHEMICAL METHODS OF ANALYSIS', '12680', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–12:25 PM', 'CX A500', 'Megan Thielges', 13, NULL, 'Lecture', '2', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'New instrumentation and techniques employed in spectrochemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 619', 'SEMINAR: ANALYTICAL CHEMISTRY', '14429', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 12:45 PM–2:00 PM', 'CH 033', 'Staff', 20, NULL, 'Seminar', '1', 'CHEMISTRY', ARRAY[]::TEXT[], 'Individual student seminars covering new methods or applications of chemical analysis or characterization. Required of all analytical chemistry majors.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 632', 'STRUCTURE, FUNCTION, AND SPECTROSCOPY OF METAL IONS IN BIOLOGICAL SYSTEMS', '35817', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'CX A500', 'Casey Van Stappen', 8, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Introduction to the field of bioinorganic chemistry and spectroscopic methods for determining structure/function relationship of metal ions in biology. Emphasis on oxygen carriers, metal ion transport and storage, as well as oxidoreductases involved in oxygen, hydrogen and nitrogen metabolism. A discussion of electron transfer proteins, photosystems, and the role of metals in medicine will also be included.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 634', 'TRANSITION METAL CHEMISTRY', '35498', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'CX A400', 'Jeremy Smith', 5, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Survey of the properties of the transition metals with emphasis on common oxidation levels, coordination geometries and compounds with "classical" ligands; "hard" and "soft" acids and bases; d-orbitals and their energies in different geometries; formation constants and the Chelate Effect, the Jahn-Teller theorem; low-, intermediate-, and high-spin systems; mixed valency; metal-ligand multiple bonding; metal-metal bonds; coordination clusters and their biological relevance.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 637', 'PHYSICAL METHODS IN STRUCTURAL CHEMISTRY', '35307', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'CX A400', 'Eric Bloch', 0, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Application of x-ray diffraction, dynamic NMR and mass spectroscopy to structural and mechanistic problems throughout the periodic table, with emphasis on what techniques are optimal for particular questions, as well as the potential weaknesses of each.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 638', 'SEMINAR INORGANIC CHEMISTRY', '14435', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 12:45 PM–2:00 PM', 'CH 033', 'Staff', 20, NULL, 'Lecture', '1–3', 'CHEMISTRY', ARRAY[]::TEXT[], 'Topics not ordinarily covered by regularly scheduled courses such as boron hydrides, x-ray diffraction, metal-metal bonds, bioinorganic chemistry, platinum metals chemistry, inorganic photochemistry, etc.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 648', 'SEMINAR ORGANIC CHEMISTRY', '14436', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 12:45 PM–2:00 PM', 'CH 033', 'Staff', 20, NULL, 'Seminar', '1', 'CHEMISTRY', ARRAY[]::TEXT[], 'Recent developments in such areas as sulfur compounds, heterocyclic, stereochemistry, polymers, and synthesis.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 668', 'SEMINAR PHYSICAL CHEMISTRY', '14437', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 12:45 PM–2:00 PM', 'CH 033', 'Staff', 20, NULL, 'Lecture', '1', 'CHEMISTRY', ARRAY[]::TEXT[], 'Topics such as chemical applications of matrix algebra and group theory, digital computing techniques, solid state chemistry, high temperature processes, electro-chemistry, theory of solutions, spectroscopy, and surface chemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 680', 'INTRODUCTION TO QUANTITATIVE BIOLOGY AND MEASUREMENT', '36353', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'CX A300', 'David Giedroc', 14, NULL, 'Lecture', '1.5', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Core topics in solution scattering methods, electron microscopy, light microscopy/imaging, and biological mass spectrometry. Course focuses on the capabilities of each type of measurement: data analysis, sensitivity, resolution, quantitation, and limitations. Introduction to cutting-edge instrumentation available for use in thesis research, research findings or new approaches used in (C689).', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 681', 'INTRODUCTION TO CHEMICAL BIOLOGY I', '8943', 'Class Status', 'MWF Monday, Wednesday, Friday 11:10 AM–12:25 PM', 'CX A500', 'Youngchan Park', 14, NULL, 'Lecture', '1.5', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Basic elements of chemical biology with a chemistry-centered focus. This course will cover peptide synthesis and ligation methods, oligonucleotide synthesis, diversity oriented synthesis and combinatorial libraries, bioorthogonal reactions, high-throughput screening methods and their use in drug discovery, and secondary metabolism.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 682', 'INTRODUCTION TO CHEMICAL BIOLOGY II', '8944', 'Class Status', 'MWF Monday, Wednesday, Friday 11:10 AM–12:25 PM', 'CX A500', 'Youngchan Park', 6, NULL, 'Lecture', '1.5', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'Basic elements of chemical biology applications and uses of technology. This course will cover microarray technology, protein labeling, chemical genetics, small molecule interactions with proteins/DNA, modulation of protein-protein interactions, RNA aptamers and molecular evolution.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 688', 'SEMINAR IN BIOCHEMISTRY', '14438', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 12:45 PM–2:00 PM', 'CH 033', 'Staff', 20, NULL, 'Seminar', '1', 'CHEMISTRY', ARRAY[]::TEXT[], 'Attendance and participation in the weekly Biochemistry Program seminar series.', ARRAY[]::TEXT[], NULL),
    ('CHEM-C 810', 'RESEARCH ANALYTICAL CHEMISTRY', '1309', 'Class Status', NULL, NULL, 'Michael Brown', 81, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
