    ('CHEM-G 599', 'THESIS RESEARCH', '5588', 'Class Status', NULL, NULL, 'Michael Brown', 10, NULL, 'Research', '0', NULL, ARRAY[]::TEXT[], 'Master''s students who have enrolled in 30 or more hours of graduate course work applicable to the degree and who have completed all other requirements of the degree except the thesis of final project of performance may enroll in G599. Requires section authorization.', ARRAY[]::TEXT[], NULL),
    ('CHEM-G 901', 'ADVANCED RESEARCH', '1313', 'Class Status', NULL, NULL, 'Michael Brown', 76, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('CHEM-H 117', 'PRINCIPLES OF CHEMISTRY AND BIOCHEMISTRY I, HONORS', '9499', 'Closed', NULL, 'MWF Monday, Wednesday, Friday 9:10 AM–10:00 AM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Regular Academic Session 8/25/2025–12/19/2025', 'CH 001 HD TBA HD TBA HD TBA', NULL, 'Lecture', 'Lecture', '3', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'An honors course for students with unusual aptitude or preparation. Covers basic principles of chemistry and biochemistry, basic mathematical and conceptual principles in atomic structure and periodic properties, molecular structure, chemical bonding, energy (thermochemistry), kinetics, equilibrium and thermodynamics.', ARRAY['Class uses IU eTexts'], NULL),
