    ('CHEM-H 127', 'PRINCIPLES OF CHEMISTRY AND BIOCHEMISTRY I LABORATORY, HONORS', '9981', 'Closed', 'Tu Tuesday 9:10 AM–10:00 AM', 'CH 001', 'Alison Wood', 0, 'Lecture', 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'Basic principles of chemistry and biochemistry that align with the topics in CHEM-J 117 and CHEM-H 117. Hands-on laboratory techniques in chemistry necessary for success in later chemistry laboratory courses, including course-based undergraduate research project.', ARRAY[]::TEXT[], NULL),
