    ('CHEM-J 341', 'PRINCIPLES OF ORGANIC CHEMISTRY I', '13440', 'Class Status', NULL, 'MWF Monday, Wednesday, Friday 10:25 AM–11:15 AM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Regular Academic Session 8/25/2025–12/19/2025', 'CH 001 HD TBA HD TBA HD TBA', NULL, 'Lecture', 'Lecture', '3', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Examines the chemistry of carbon compounds. Emphasizes structural, reactivity, and mechanistic principles necessary to understand syntheses and reactions of major classes of monofunctional compounds at the level appropriate for chemistry and biochemistry majors.', ARRAY['Class uses IU eTexts'], NULL),
