    ('CHEM-J 343', 'ORGANIC CHEMISTRY LABORATORY I FOR MAJORS', '9614', 'Class Status', 'Th Thursday 12:40 PM–4:40 PM', 'CH 145', 'Staff', 5, 'Laboratory', 'Lecture', '2', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Covers same material as CHEM-C 343 at the level required for chemistry and biochemistry majors.', ARRAY['Class uses IU eTexts'], NULL),
    ('CHEM-J 343', 'ORGANIC CHEMISTRY LABORATORY I FOR MAJORS', '9610', 'Closed', 'M Monday 5:20 PM–9:20 PM', 'CH 145', 'Staff', 0, 'Laboratory', 'Lecture', '2', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Covers same material as CHEM-C 343 at the level required for chemistry and biochemistry majors.', ARRAY['Class uses IU eTexts'], NULL),
    ('CHEM-J 343', 'ORGANIC CHEMISTRY LABORATORY I FOR MAJORS', '9612', 'Closed', 'W Wednesday 5:20 PM–9:20 PM', 'CH 145', 'Staff', 0, 'Laboratory', 'Lecture', '2', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Covers same material as CHEM-C 343 at the level required for chemistry and biochemistry majors.', ARRAY['Class uses IU eTexts'], NULL),
    ('CHEM-M 501', 'FUNDAMENTALS OF MATERIALS I: MAKING, MEASURING, AND MODELING', '36875', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'CX A500', 'Samantha Harvey', 20, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'To introduce the student to techniques for fabrication, characterization, and modeling of materials with an emphasis on nanostructures. Methods (top down) for the creation and characterization of nanostructures; band structure, conductivity, optical properties, and quantum confinement, assembly, liquids, and phas transitions.', ARRAY[]::TEXT[], NULL),
    ('CHEM-M 503', 'SUPRAMOLECULAR CHEMISTRY', '12591', 'Class Status', 'MWF Monday, Wednesday, Friday 12:45 PM–2:00 PM', 'CX A500', 'Amar Flood', 14, NULL, 'Lecture', '3', 'CHEMISTRY ADDITION', ARRAY[]::TEXT[], 'A one-semester overview of bottom-up fabrication of functional materials. Emphasis on the chemistry of molecularly defined assemblies constructed via non-covalent interactions. Topics include synthetic strategies and physical properties; recognition, catalysis, sensing, switching, transport, and actuation; electron transfer and energy transfer; interfacial assemblies; mesoporous materials; polymers, dendrimers and liquid crystals.', ARRAY[]::TEXT[], NULL),
    ('CHEM-M 608', 'SEMINAR: MATERIALS CHEMISTRY', '14439', 'Class Status', 'MTuWThF Monday, Tuesday, Wednesday, Thursday, Friday 12:45 PM–2:00 PM', 'CH 033', 'Staff', 20, NULL, 'Seminar', '1', 'CHEMISTRY', ARRAY[]::TEXT[], 'Topics such as electrochemistry, biomaterials, polymers, solid state chemistry, computational chemistry, micro/nanofabrication, and environmental chemistry considered from the perspective of materials chemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-M 800', 'MATERIALS CHEMISTRY RESEARCH SEMINAR', '4355', 'Class Status', 'F Friday 2:20 PM–3:35 PM', 'BH 008', 'Jeffrey Zaleski', 19, NULL, 'Seminar', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The preparation and presentation of student research lectures based on current journals and other research literature in materials chemistry and related areas on topics not closely related to the student''s own research.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 331', 'INTERMEDIATE INORGANIC CHEMISTRY', '9516', 'Class Status', NULL, 'MWF Monday, Wednesday, Friday 12:45 PM–1:35 PM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Regular Academic Session 8/25/2025–12/19/2025', 'CH 122 HD TBA HD TBA HD TBA', NULL, 'Lecture', 'Lecture', '3', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on structure, bonding, and reaction mechanisms of inorganic compounds using molecular orbital theory as a basis for metal-ligand interaction. Compounds covered include transition metal coordination compounds, organometallic compounds, and bioinorganic complexes. Other topics include redox chemistry, nuclear chemistry, and an introduction to solid-state chemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 331', 'INTERMEDIATE INORGANIC CHEMISTRY', '9518', 'Class Status', 'Th Thursday 10:25 AM–11:15 AM', 'BH 330', 'Staff', 2, 'Discussion', 'Lecture', '3', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on structure, bonding, and reaction mechanisms of inorganic compounds using molecular orbital theory as a basis for metal-ligand interaction. Compounds covered include transition metal coordination compounds, organometallic compounds, and bioinorganic complexes. Other topics include redox chemistry, nuclear chemistry, and an introduction to solid-state chemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 331', 'INTERMEDIATE INORGANIC CHEMISTRY', '9519', 'Class Status', 'Th Thursday 3:10 PM–4:00 PM', 'BH 330', 'Staff', 5, 'Discussion', 'Lecture', '3', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on structure, bonding, and reaction mechanisms of inorganic compounds using molecular orbital theory as a basis for metal-ligand interaction. Compounds covered include transition metal coordination compounds, organometallic compounds, and bioinorganic complexes. Other topics include redox chemistry, nuclear chemistry, and an introduction to solid-state chemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 331', 'INTERMEDIATE INORGANIC CHEMISTRY', '10449', 'Class Status', 'Th Thursday 6:40 PM–7:30 PM', 'BH 346', 'Staff', 19, 'Discussion', 'Lecture', '3', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on structure, bonding, and reaction mechanisms of inorganic compounds using molecular orbital theory as a basis for metal-ligand interaction. Compounds covered include transition metal coordination compounds, organometallic compounds, and bioinorganic complexes. Other topics include redox chemistry, nuclear chemistry, and an introduction to solid-state chemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 331', 'INTERMEDIATE INORGANIC CHEMISTRY', '10450', 'Class Status', 'Th Thursday 8:00 AM–8:50 AM', 'BH 330', 'Staff', 7, 'Discussion', 'Lecture', '3', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on structure, bonding, and reaction mechanisms of inorganic compounds using molecular orbital theory as a basis for metal-ligand interaction. Compounds covered include transition metal coordination compounds, organometallic compounds, and bioinorganic complexes. Other topics include redox chemistry, nuclear chemistry, and an introduction to solid-state chemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 331', 'INTERMEDIATE INORGANIC CHEMISTRY', '9517', 'Closed', 'Th Thursday 9:10 AM–10:00 AM', 'BH 330', 'Staff', 0, 'Discussion', 'Lecture', '3', 'CHEMISTRY, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Focuses on structure, bonding, and reaction mechanisms of inorganic compounds using molecular orbital theory as a basis for metal-ligand interaction. Compounds covered include transition metal coordination compounds, organometallic compounds, and bioinorganic complexes. Other topics include redox chemistry, nuclear chemistry, and an introduction to solid-state chemistry.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 337', 'INTERMEDIATE INORGANIC CHEMISTRY LABORATORY', '9520', 'Class Status', 'Tu Tuesday 12:45 PM–1:35 PM', 'CH 001', 'Norman Dean', 7, 'Lecture', 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'Focuses on the application of foundational material covered in CHEM-N 331. Lab works includes synthesis of transition metal complexes and investigation of structure and bonding using multiple spectroscopic techniques. Base-level computations will be carried out in support of lab work. Also emphasizes the development of professional writing skills.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 337', 'INTERMEDIATE INORGANIC CHEMISTRY LABORATORY', '9521', 'Class Status', 'Th Thursday 11:30 AM–2:30 PM', 'CH 027', 'Staff', 1, 'Laboratory', 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'Focuses on the application of foundational material covered in CHEM-N 331. Lab works includes synthesis of transition metal complexes and investigation of structure and bonding using multiple spectroscopic techniques. Base-level computations will be carried out in support of lab work. Also emphasizes the development of professional writing skills.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 337', 'INTERMEDIATE INORGANIC CHEMISTRY LABORATORY', '9524', 'Class Status', 'Th Thursday 6:30 PM–9:30 PM', 'CH 027', 'Staff', 6, 'Laboratory', 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'Focuses on the application of foundational material covered in CHEM-N 331. Lab works includes synthesis of transition metal complexes and investigation of structure and bonding using multiple spectroscopic techniques. Base-level computations will be carried out in support of lab work. Also emphasizes the development of professional writing skills.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 337', 'INTERMEDIATE INORGANIC CHEMISTRY LABORATORY', '9522', 'Closed', 'Th Thursday 3:00 PM–6:00 PM', 'CH 027', 'Staff', 0, 'Laboratory', 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'Focuses on the application of foundational material covered in CHEM-N 331. Lab works includes synthesis of transition metal complexes and investigation of structure and bonding using multiple spectroscopic techniques. Base-level computations will be carried out in support of lab work. Also emphasizes the development of professional writing skills.', ARRAY[]::TEXT[], NULL),
    ('CHEM-N 800', 'INORGANIC CHEMISTRY RESEARCH SEMINAR', '3356', 'Class Status', 'F Friday 2:20 PM–3:35 PM', 'BH 008', 'Jeffrey Zaleski', 19, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The preparation and presentation of second year inorganic chemistry student research project. Skills to be developed include creativity, critical and analytical thinking, and persuasive and modern presentation methods.', ARRAY[]::TEXT[], NULL),
    ('CHEM-P 360', 'PHYSICAL CHEMISTRY FOR BIOCHEMISTS', '9527', 'Class Status', NULL, 'MWF Monday, Wednesday, Friday 11:35 AM–12:25 PM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Tu Tuesday 7:15 PM–9:15 PM Regular Academic Session 8/25/2025–12/19/2025', 'BH 008 HD TBA HD TBA HD TBA HD TBA', NULL, 'Lecture', 'Lecture', '3', 'BALLANTINE HALL, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Covers elements of thermodynamics, reaction kinetics, molecular quantum states and spectroscopy, focusing on an intuitive approach to these topics at an intermediate level of mathematical rigor.', ARRAY[]::TEXT[], NULL),
    ('CHEM-P 360', 'PHYSICAL CHEMISTRY FOR BIOCHEMISTS', '9528', 'Class Status', 'Th Thursday 12:45 PM–1:35 PM', 'BH 330', 'Staff', 1, 'Discussion', 'Lecture', '3', 'BALLANTINE HALL, BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Covers elements of thermodynamics, reaction kinetics, molecular quantum states and spectroscopy, focusing on an intuitive approach to these topics at an intermediate level of mathematical rigor.', ARRAY[]::TEXT[], NULL),
    ('CHEM-P 800', 'PHYSICAL CHEMISTRY RESEARCH SEMINAR', '3357', 'Class Status', 'F Friday 2:20 PM–3:35 PM', 'BH 008', 'Jeffrey Zaleski', 19, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The preparation and presentation of student research lectures based on current journals and other research literature in physical chemistry and related areas on topics not closely related to the student''s own research.', ARRAY[]::TEXT[], NULL),
    ('CHEM-R 800', 'ORGANIC CHEMISTRY RESEARCH SEMINAR', '3358', 'Class Status', 'F Friday 2:20 PM–3:35 PM', 'BH 008', 'Jeffrey Zaleski', 19, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Major topics in contemporary organic chemistry will be examined. A list of subjects will be provided at the beginning of the year. Facilitates the transition from a highly structured learning environment to the period of independent scholarship that is required in the final stages of the doctoral program.', ARRAY[]::TEXT[], NULL),
    ('CHEM-T 525', 'FORENSIC CHEMISTRY', '32704', 'Class Status', NULL, 'OL ONLINE', 'Linda Wozniewski', 15, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Chemical analysis of drugs, polymers, fingerprints, paints, inks, explosives, accelerants, glass, blood, DNA, soil, and other evidence found at a crime scene.', ARRAY[]::TEXT[], NULL),
    ('CHEM-T 530', 'ORGANIC SPECTROSCOPY', '32638', 'Class Status', NULL, 'OL ONLINE', 'Mohammad Hossain', 16, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This is a course in Organic Spectroscopy. This course is intended to give students a more complete picture of how spectroscopic methods (IR, UV, NMR, mass spectroscopy, and other methods) are used to elucidate the structure of complex organic molecules.', ARRAY[]::TEXT[], NULL),
    ('CHEM-X 170', 'CHEMISTRY COMMUNITY OUTREACH SEMINAR', '34326', 'Class Status', 'Th Thursday 1:55 PM–2:45 PM', 'CH 311', 'Benjamin Burlingham', 3, NULL, 'Lecture', '2', 'CHEMISTRY', ARRAY[]::TEXT[], 'Provides opportunities to work within the community to foster interest, knowledge, and appreciation of the sciences. Includes preparation and execution of demonstrations and in-class lessons at primary and secondary school levels.', ARRAY[]::TEXT[], NULL),
