    ('CJUS-P 330', 'CRIMINAL JUSTICE ETHICS', '14612', 'Class Status', 'Tu Tuesday 5:30 PM–8:00 PM', 'BH 208', 'Lawrence Hilton', 2, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Study of major ethical theories with emphasis on their application to components of the criminal justice system. Personal and professional dilemmas and problem-solving will be emphasized.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 332', 'CRIMINAL PROSECUTION', '13337', 'Closed', 'TuTh Tuesday, Thursday 4:30 PM–5:45 PM', 'BH 110', 'Mary Ellen Diekhoff', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines all aspects of criminal prosecution, including decisions pertaining to the filing of criminal charges, negotiated plea agreements, and attaining of criminal convictions. Discusses how a prosecutor''s office interacts with other divisions of the criminal justice system such as the courts, law enforcement and the defense bar.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 333', 'FORENSIC EVIDENCE COLLECTION, ANALYSIS, AND USE IN CRIMINAL PROSECUTIONS', '30220', 'Class Status', 'W Wednesday 6:40 PM–9:10 PM', 'GY 1045', 'William Mc Coskey', 1, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Covers various topics related to criminal forensics evidence. Emphasis on collection, analysis and tactical use of forensic evidence at trial, including admission and use in court and common challenges by criminal defendants. Issues of privacy rights, search and seizure, investigative methods, case preparation, and methods of proof also explored.', ARRAY['Class uses IU eTexts'], NULL),
    ('CJUS-P 371', 'CRIMINAL PROCEDURE', '5241', 'Closed', 'W Wednesday 4:20 PM–6:50 PM', 'GA 1112', 'Steve Presson', 0, NULL, 'Lecture', '3', 'GLOBAL & INTERNATIONAL STUDIES', ARRAY[]::TEXT[], 'Fundamental legal problems of criminal justice system processes. Emphasis on pretrial phases of American system procedures.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('CJUS-P 399', 'READINGS FOR HONORS', '1326', 'Class Status', NULL, NULL, 'Jonathan Brauer', 5, NULL, 'Readings', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CJUS-P 408', 'MASS IMPRISONMENT', '11997', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SY 002', 'Bonnie Ernst', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'From 1970 to 2010, the United States quintupled its prison population. This course investigates the factors (cultural, legal, political, and economic) that led to the incarceration boom and provides students with the empirical and normative tools to evaluate its causes and consequences.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('CJUS-P 411', 'CRIMINAL JUSTICE MANAGEMENT', '14992', 'Closed', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 307', 'Bradley Seifers', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examination of the ideas and concepts from various disciplines contributing to modern administrative theory, and translation of these insights to the management of criminal justice agencies.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
Class uses IU eTexts'], NULL),
    ('CJUS-P 414', 'ADOLESCENTS AND THE LAW', '11143', 'Closed', 'W Wednesday 4:20 PM–6:50 PM', 'BH 245', 'Roger Levesque', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examination of the place of adolescents in American law and policy. Consideration of adolescents'' rights, limits to these, and their relationship to socio-cultural images of adolescents.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('CJUS-P 415', 'CRIME AND MADNESS', '6016', 'Closed', 'M Monday 5:30 PM–8:00 PM', 'BH 307', 'Stacy Uliana', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'The study of the chronic mentally ill and of career criminals. Examination of the groups so labeled, the responses of the criminal justice and mental health systems to them, and their movement back and forth between the streets, prisons, and psychiatric centers.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('CJUS-P 426', 'JUVENILE DELINQUENCY', '11999', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'JH 001', 'Jennifer O''Neill', 0, NULL, 'Lecture', '3', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Focus on the critical analysis of the impact of significant individual, social, and institutional influences on delinquency including the family, delinquent peer groups, schools, and the community to respond to the question, "What causes juveniles to break the law?"', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('CJUS-P 433', 'LAW OF WAR', '13338', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SY 001', 'Todd Burkhardt', 0, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Provides an understanding of the laws of war and how they are foundational to society. Engages in the study of international humanitarian law, formal justice systems, the U.S. military, and international organizations to highlight the relationship between law, social context, and the morality that underpins restrictions and accountability in war.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('CJUS-P 440', 'PRIVACY, LAW AND SECURITY', '14130', 'Class Status', 'Tu Tuesday 4:20 PM–6:50 PM', 'SY 002', 'Roger Levesque', 1, NULL, 'Seminar', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Exploration of the legal underpinnings of the concept of privacy and their role in ensuring individual and civic security.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('CJUS-P 457', 'SEMINAR ON WHITE-COLLAR CRIME', '11174', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'WH 009', 'Fiona Chan', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'The nature and incidence of white-collar crime. In addition to studying the etiological theories relating to white-collar crime, the course will also focus on both the criminal and civil (regulatory) processes used to control corporate, organizational, and elite misconduct.', ARRAY['COLL (CASE) S&H Breadth of Inquiry credit'], NULL),
    ('CJUS-P 493', 'SEMINAR IN CRIMINAL JUSTICE', '12000', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'SY 003', 'Bruce Sales', 2, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Intensive study and analysis of selected problems in criminal justice. Topics will vary.', ARRAY['COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('CJUS-P 499', 'SENIOR HONORS THESIS', '1327', 'Class Status', NULL, NULL, 'Jonathan Brauer', 5, NULL, 'Readings', '3–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CJUS-P 502', 'PROSEMINAR: CRIMINAL JUSTICE II', '12026', 'Class Status', 'W Wednesday 9:10 AM–11:40 AM', 'SY 312', 'Jonathan Brauer', 5, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Theories of crime and delinquency.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 503', 'PROSEMINAR IN CRIMINAL JUSTICE', '12911', 'Class Status', 'M Monday 9:00 AM–9:50 AM', 'SY 312', 'Miriam Northcutt Bohmert', 3, NULL, 'Seminar', '1', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Discussion-based course that covers the (sometimes hidden) goals of graduate school and prepares graduate students for academic and professional success in Criminal Justice.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 505', 'PROSEMINAR: LAUNCHING A CJUS ACADEMIC CAREER', '12909', 'Class Status', 'M Monday 10:00 AM–10:50 AM', 'SY 312', 'Miriam Northcutt Bohmert', 3, NULL, 'Seminar', '1', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course will discuss your professional career as it''s related to various unspoken elements of the graduate career that position some students to be better prepared than others. Building on previous seminars, you will take steps to better position yourself to reach your goals.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 512', 'CORRECTIONS', '30218', 'Class Status', 'Tu Tuesday 1:55 PM–4:25 PM', 'SY 105', 'Bonnie Ernst', 2, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Reviews historical and philosophical bases of correctional system and examines components of system (community corrections, jails and prisons). Focuses on the structure and functions of the corrections system with particular attention to the role of broader social forces on the development and operation of the system.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 594', 'INTRODUCTION TO RESEARCH METHODS', '30219', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 138', 'Miriam Northcutt Bohmert', 6, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Research methodology in criminal justice. Research design, scientific methods, quantitative/qualitative applications, ethical questions, and the role of the criminal justice researcher.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 599', 'RESEARCH PRACTICUM', '1328', 'Class Status', NULL, NULL, 'Miriam Northcutt Bohmert', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Required course for Ph.D. students. Designed to provide guided experience in conducting research independently. The topic and scope of the student''s effort must be approved in advance by the professor.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 619', 'CRIME AND PUBLIC POLICY', '14170', 'Class Status', 'W Wednesday 10:25 AM–12:55 PM', 'SY 0009', 'Molly Block', 9, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Examines processes by which societies define crime and develop responses to crime. Particular attention is given to case studies of how particular policies were developed and implemented, and what effects policies produced.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 694', 'RESEARCH IN CRIMINAL JUSTICE', '1329', 'Class Status', NULL, NULL, 'Miriam Northcutt Bohmert', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CJUS-P 694', 'RESEARCH IN CRIMINAL JUSTICE', '3209', 'Class Status', NULL, NULL, 'Miriam Northcutt Bohmert', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CJUS-P 794', 'THESIS (A.M.)', '1330', 'Closed', NULL, NULL, 'Miriam Northcutt Bohmert', 0, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CJUS-P 851', 'READINGS IN CRIMINAL JUSTICE', '1331', 'Class Status', NULL, NULL, 'Miriam Northcutt Bohmert', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Individualized readings on topics not covered in regular course offerings.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 851', 'READINGS IN CRIMINAL JUSTICE', '3210', 'Class Status', NULL, NULL, 'Miriam Northcutt Bohmert', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Individualized readings on topics not covered in regular course offerings.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 855', 'RESEARCH IN CRIMINAL JUSTICE', '1332', 'Class Status', NULL, NULL, 'Miriam Northcutt Bohmert', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'The student is expected to make substantial progress toward identification of an eventual dissertation project.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 855', 'RESEARCH IN CRIMINAL JUSTICE', '6995', 'Class Status', NULL, NULL, 'Miriam Northcutt Bohmert', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'The student is expected to make substantial progress toward identification of an eventual dissertation project.', ARRAY[]::TEXT[], NULL),
    ('CJUS-P 859', 'PH D THESIS', '1333', 'Class Status', NULL, NULL, 'Miriam Northcutt Bohmert', 9, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CJUS-X 371', 'TEACHING INTERNSHIP', '5525', 'Class Status', NULL, NULL, 'Jonathan Brauer', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised experience in assisting in an undergraduate course. Discussion of good teaching practices. Students will complete a project related to the aims of the course in which they are assisting. Students and instructor will complete a form agreeing on responsibilities at the beginning of the relevant semester.', ARRAY[]::TEXT[], NULL),
    ('CJUS-X 477', 'FIELD EXPERIENCE IN CRIMINAL JUSTICE', '7469', 'Class Status', NULL, NULL, 'Molly Block', 21, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Field experience with directed readings and writing.', ARRAY[]::TEXT[], NULL),
    ('CJUS-X 490', 'INDIVIDUAL READINGS', '7470', 'Class Status', NULL, NULL, 'Jonathan Brauer', 15, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Individual study project under guidance of faculty member or committee. Students and instructor will complete a form agreeing on responsibilities at the beginning of the relevant semester.', ARRAY[]::TEXT[], NULL),
    ('CJUS-X 498', 'RESEARCH IN CRIMINAL JUSTICE', '7471', 'Class Status', NULL, NULL, 'Jonathan Brauer', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Active participation in a research project and related activities under the direction of a faculty member. Students and instructor will complete a form agreeing on responsibilities at the beginning of the relevant semester.', ARRAY[]::TEXT[], NULL),
    ('CLAS-C 102', 'ROMAN CULTURE', '1334', 'Class Status', 'TuTh Tuesday, Thursday 8:00 AM–9:15 AM', 'MY 130', 'Bridget Balint, Kate Cota', 1, NULL, 'Lecture', '3', 'MYERS HALL', ARRAY[]::TEXT[], 'CLAS-C 102 explores the culture and history of ancient Rome, both as a distinct past society, and as a cultural force that continues to shape modern life. We will focus on several questions: How was Roman society organized? How did Rome''s particular history shape how Roman society developed? What was daily life like for various social classes (elite and poor, free and slace, etc.)? What was the role of religion? How do we interpret different types of evidence about he past, including written and archaeological sources? How does ancient Rome continue to shape the world we inhabit today?', ARRAY['IUB GenEd A&H credit
IUB GenEd World Culture credit
COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('CLAS-C 102', 'ROMAN CULTURE', '15323', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 120', 'Julia Mebane, Simon Kaplan', 0, NULL, 'Lecture', '3', 'MYERS HALL', ARRAY[]::TEXT[], 'CLAS-C 102 explores the culture and history of ancient Rome, both as a distinct past society, and as a cultural force that continues to shape modern life. We will focus on several questions: How was Roman society organized? How did Rome''s particular history shape how Roman society developed? What was daily life like for various social classes (elite and poor, free and slace, etc.)? What was the role of religion? How do we interpret different types of evidence about he past, including written and archaeological sources? How does ancient Rome continue to shape the world we inhabit today?', ARRAY['IUB GenEd A&H credit
