    ('CLAS-C 209', 'MED TERMS FROM GREEK & LATIN', '1336', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:20 PM', 'JH 065', 'Chelsea Silverman', 1, NULL, 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Basic vocabulary of some 1,000 words, together with materials for formation of compounds, enables student to build working vocabulary of several thousand words. Designed for those intending to specialize in medicine, nursing, dentistry, or microbiology.', ARRAY[]::TEXT[], NULL),
    ('CLAS-C 209', 'MED TERMS FROM GREEK & LATIN', '8341', 'Class Status', 'MW Monday, Wednesday 9:10 AM–10:00 AM', 'JH 065', 'Tom Pappas', 1, NULL, 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Basic vocabulary of some 1,000 words, together with materials for formation of compounds, enables student to build working vocabulary of several thousand words. Designed for those intending to specialize in medicine, nursing, dentistry, or microbiology.', ARRAY[]::TEXT[], NULL),
    ('CLAS-C 209', 'MED TERMS FROM GREEK & LATIN', '12016', 'Closed', 'MW Monday, Wednesday 11:35 AM–12:25 PM', 'JH 065', 'Zofia Ahmad', 0, NULL, 'Lecture', '2', 'BIOLOGY BUILDING', ARRAY[]::TEXT[], 'Basic vocabulary of some 1,000 words, together with materials for formation of compounds, enables student to build working vocabulary of several thousand words. Designed for those intending to specialize in medicine, nursing, dentistry, or microbiology.', ARRAY[]::TEXT[], NULL),
    ('CLAS-C 211', 'ANCIENT ATHLETICS: GREEKS, ROMANS, AND US', '11097', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 215', 'Nicholas Blackwell', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to Greco-Roman culture through sports and spectacle (e.g. ancient Olympics, gladiators, chariot racing) and the literary and material remains associated with them. Examines how sports shaped ancient identities and behavior as well as reflected their cultural context.', ARRAY['IUB GenEd A&H credit
