    ('CLAS-C 399', 'READING FOR HONORS', '4763', 'Class Status', NULL, NULL, 'Cynthia Bannon', 3, NULL, 'Readings', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CLAS-C 413', 'THE ART AND ARCHAEOLOGY OF GREECE', '29421', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 125', 'Nicholas Blackwell', 1, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Art and archaeology of Greece from about 1000 B.C. through the Hellenistic period. Special attention given to the development of Greek architecture, sculpture, and vase painting. Continuation of C412.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CLAS-C 419', 'THE ART AND ARCHAEOLOGY OF POMPEII', '29425', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SB 220', 'Lindsey Mazurek', 0, NULL, 'Lecture', '3', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Survey of archaeological evidence of the best-preserved ancient city, buried under the ashes of Mt. Vesuvius in AD 79. Learn about everyday life in a Roman seaside town. Topics including urban development, gladiators, theater, the lives of women and slaves, commerce, religion, art history, the ethics of preserving disaster sites, and more.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CLAS-C 499', 'READING FOR HONORS', '1337', 'Class Status', NULL, NULL, 'Cynthia Bannon', 5, NULL, 'Readings', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CLAS-C 503', 'THE ANCIENT CITY', '29426', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'SB 220', 'Lindsey Mazurek', 1, NULL, 'Lecture', '4', 'STUDENT BUILDING (FRANCES MORG', ARRAY[]::TEXT[], 'Survey of the topography and monuments of one of the major cities - Athens, Corinth, Rome, Ostia, for example - of the classical world. Introduces the student to the individual city and its monuments, through the monuments provides a better understanding of urbanism through the history of the specific city, its statesmen and authors.', ARRAY[]::TEXT[], NULL),
    ('CLAS-C 513', 'THE ART AND ARCHAEOLOGY OF GREECE', '29424', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'LH 125', 'Nicholas Blackwell', 4, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Art and archaeology of Greece from about 1000 B.C. through the Hellenistic period. Special attention given to the development of Greek architecture, sculpture, and vase painting.', ARRAY[]::TEXT[], NULL),
    ('CLAS-C 875', 'RESEARCH IN GREEK OR LATIN', '8109', 'Class Status', NULL, NULL, 'Cynthia Bannon', 7, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CLAS-C 880', 'PH D THESIS', '1338', 'Class Status', NULL, NULL, 'Cynthia Bannon', 4, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CLAS-G 100', 'ELEMENTARY GREEK I', '1339', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 147', 'Matthew Christ', 8, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Fundamentals of both classical and koine Greek; develops reading comprehension; selections from classical authors and the New Testament.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CLAS-G 200', 'INTERMEDIATE GREEK', '1340', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 314', 'Cynthia Bannon', 13, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continuation of G150. Advanced grammatical, morphological, and lexical components of Ancient Greek. Readings in Plato.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CLAS-G 407', 'GREEK HISTORIANS', '29431', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SY 105', 'Matthew Christ', 3, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Selections from Herodotus and Thucydides, with attention to the authors'' literary style, their conception of history and the causation of events, and their portrayal of individuals and states.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CLAS-G 500', 'ELEMENTARY GREEK I', '1341', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 11:35 AM–12:25 PM', 'BH 147', 'Matthew Christ', 8, NULL, 'Lecture', '2', 'BALLANTINE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CLAS-G 510', 'READINGS IN GREEK HISTORIANS', '29432', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'SY 105', 'Matthew Christ', 3, NULL, 'Lecture', '4', 'SYCAMORE HALL', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CLAS-G 600', 'INTERMEDIATE GREEK', '1342', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'BH 314', 'Cynthia Bannon', 13, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Continuation of G550. Advanced grammatical, morphological, and lexical components of Ancient Greek. Readings in Plato.', ARRAY[]::TEXT[], NULL),
    ('CLAS-G 803', 'SUPERVISED READING PROGRAM', '1343', 'Class Status', NULL, NULL, 'Cynthia Bannon', 8, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CLAS-G 901', 'ADVANCED RESEARCH', '1344', 'Class Status', NULL, NULL, 'Cynthia Bannon', 9, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('CLAS-L 100', 'ELEMENTARY LATIN I', '1345', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 9:10 AM–10:00 AM', 'BH 232', 'Bridget Balint, Kristof Szabo', 1, NULL, 'Drill', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Fundamentals of the language; develops direct reading comprehension of Latin.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CLAS-L 100', 'ELEMENTARY LATIN I', '1346', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 10:25 AM–11:15 AM', 'BH 246', 'Bridget Balint, Margaret Kammerer', 7, NULL, 'Drill', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Fundamentals of the language; develops direct reading comprehension of Latin.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CLAS-L 150', 'ELEMENTARY LATIN II', '3091', 'Class Status', 'MTuWTh Monday, Tuesday, Wednesday, Thursday 9:10 AM–10:00 AM', 'BH 133', 'Bridget Balint, Jennifer Murphy', 12, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Fundamentals of the language; develops direct reading comprehension of Latin.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CLAS-L 200', 'SECOND-YEAR LATIN I', '1347', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'ED 1084', 'Bridget Balint, Alec Smitten', 6, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Provides further understanding of Latin vocabulary and grammar, with emphasis placed on reading the original texts of Latin authors. Students also continue their study of Ancient Roman society, literature, religion, and culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CLAS-L 200', 'SECOND-YEAR LATIN I', '37280', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'ED 1220', 'Elise Poppen', 12, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Provides further understanding of Latin vocabulary and grammar, with emphasis placed on reading the original texts of Latin authors. Students also continue their study of Ancient Roman society, literature, religion, and culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CLAS-L 250', 'SECOND-YEAR LATIN II', '1348', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 134', 'Michael W. Lundell', 13, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'L250 provides further understanding of Latin vocabulary and grammar, with emphasis placed on reading the original texts of Latin authors. Students also continue their study of Ancient Roman society, literature, religion, and culture.', ARRAY['IUB GenEd World Language class'], NULL),
    ('CLAS-L 311', 'SALLUST', '29427', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 217', 'Julia Mebane', 14, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Readings from the major works of Sallust, Catilina and Jurgurtha, with emphasis on syntax as well as analysis of Sallust''s writing in its historical and literary contexts.', ARRAY[]::TEXT[], NULL),
    ('CLAS-L 409', 'READINGS IN MEDIEVAL LATIN', '13331', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 219', 'Bridget Balint', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Survey of the secular and religious literature of the Middle Ages; discussion of the later development of the Latin language; selections from such authors as Gregory of Tours, Isidore of Seville, Paul the Deacon, Matthew Paris, and Bernard of Cluny.', ARRAY[]::TEXT[], NULL),
    ('CLAS-L 410', 'ADVANCED PROSE COMPOSITION', '29429', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 240', 'Cynthia Bannon', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Exercises in composition requiring control of principal features of Latin syntax.', ARRAY[]::TEXT[], NULL),
    ('CLAS-L 505', 'LATIN GRAMMAR, COMPOSITION AND RAPID READING', '29430', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 240', 'Cynthia Bannon', 9, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Exercises in Latin composition requiring control of principle features of Latin syntax and sight reading of previously unseen passages leading to rapid mastery of texts.', ARRAY[]::TEXT[], NULL),
    ('CLAS-L 524', 'INTRODUCTION TO SALLUST', '29428', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 217', 'Julia Mebane', 14, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Readings from the major works of Sallust, Catilina and Jurgurtha, with emphasis on syntax as well as analysis of Sallust''s writing in its historical and literary contexts.', ARRAY[]::TEXT[], NULL),
    ('CLAS-L 532', 'INTRODUCTION TO MEDIEVAL LATIN', '13332', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 219', 'Bridget Balint', 7, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Survey of the secular and religious literature of the Middle Ages; discussion of the later development of the Latin language; selections from such authors as Gregory of Tours, Isidore of Seville, Paul the Deacon, Matthew Paris, and Bernard of Cluny.', ARRAY[]::TEXT[], NULL),
    ('CLAS-L 803', 'SUPERVISED READING PROGRAM', '1349', 'Class Status', NULL, NULL, 'Cynthia Bannon', 6, NULL, 'Independent Study', '1–4', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('CLAS-X 473', 'INTERNSHIP IN CLASSICAL STUDIES', '8377', 'Class Status', NULL, NULL, 'Cynthia Bannon', 5, NULL, 'Lecture', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised work experience in a professional work setting in which a student applies skills and knowledge derived from Classical Studies.', ARRAY[]::TEXT[], NULL),
    ('CLAS-X 476', 'PRACTICUM IN CLASSICAL STUDIES', '8378', 'Class Status', NULL, NULL, 'Cynthia Bannon', 5, NULL, 'Practicum', '1–3', NULL, ARRAY[]::TEXT[], 'Supervised work and academic experience in which a student applies skills and knowledge closely related to Classical Studies in a real-world environment, for example, through curatorial work in a museum.', ARRAY[]::TEXT[], NULL),
    ('CLAS-X 490', 'INDIVIDUAL READING IN CLASSICS', '7089', 'Class Status', NULL, NULL, 'Cynthia Bannon', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Provides opportunity for students to pursue independent study in a Classical Civilization topic related to a) culture and literature or b) art and archaeology.', ARRAY[]::TEXT[], NULL),
    ('CLAS-X 491', 'INDIVIDUAL READING IN GREEK', '7090', 'Class Status', NULL, NULL, 'Cynthia Bannon', 5, NULL, 'Readings', '1–3', NULL, ARRAY[]::TEXT[], 'Independent, guided readings in Greek from selected authors, paying close attention to rhetorical figures, generic conventions, stylistic features, and motifs and themes. May also include exploration of how texts reflect and respond to socio-political developments and particular audiences.', ARRAY[]::TEXT[], NULL),
    ('CLAS-X 492', 'INDIVIDUAL READING IN LATIN', '7091', 'Class Status', NULL, NULL, 'Cynthia Bannon', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Independent, guided readings in Latin from selected authors, paying close attention to rhetorical figures, generic conventions, stylistic features, and motifs and themes. May also include exploration of how texts reflect and respond to socio-political developments and particular audiences.', ARRAY[]::TEXT[], NULL),
    ('CLLC-L 102', 'EDIBLE WILD PLANTS', '31594', 'Closed', 'TuTh Tuesday, Thursday 3:10 PM–5:10 PM', 'EO C110', 'Monique Philpot', 0, NULL, 'Seminar', '1', 'EDMONDSON HALL', ARRAY[]::TEXT[], 'Using the fields and forests of Bloomington as a classroom, students spend time outdoors observing, learning, drawing, collecting, and tasting edible wild plants. Students will discover where edible wild plants are growing and learn how to collect and use them in recipes as they assess sustainable practices.', ARRAY['COLLINS-LLC PROGRAM'], NULL),
