    ('CLLC-X 273', 'COLLINS INTERNSHIP IN STUDENT SELF-GOVERNANCE AND MANAGEMENT', '9073', 'Class Status', NULL, NULL, 'Lara Kriegel', 10, NULL, 'Internship', '1–3', NULL, ARRAY[]::TEXT[], 'Students expand their engagement in Collins residence or LLC self-government, in educational programming, arts management, or other activities, by reflecting on their work through journal-keeping and a final report. Meetings with the LLC Director (or designated instructor of record) provide opportunities to gain critical reflections on the experience and to learn how to apply learned skills to post-college experience.', ARRAY['COLLINS-LLC PROGRAM'], NULL),
    ('CLLC-X 490', 'INDEPENDENT STUDY', '3262', 'Class Status', NULL, NULL, 'Lara Kriegel', 30, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individuals or groups of two or more students may put together their own course of study on a topic of common interest, under the supervision of an appropriate faculty member.', ARRAY['COLLINS-LLC PROGRAM'], NULL),
