    ('CMLT-C 205', 'COMPARATIVE LITERARY ANALYSIS', '13686', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'BH 214', 'Jeffrey Johnson', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduction to basic concepts of literary criticism through comparative close readings of texts from a variety of literary genres - fiction, poetry, drama, essay - from diverse traditions.', ARRAY['IUB GenEd A&H credit
