    ('CMLT-C 216', 'SCIENCE FICTION, FANTASY, AND THE WESTERN TRADITION', '11052', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'WH 005', 'Noel Wheeler', 0, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Historical and comparative survey of science fiction and fantasy narrative from antiquity to the present. The origin of scientific narrative in ancient Greek literature, its relation to ancient myths, and its history and development. Emphasis on philosophical, cognitive, and scientific aspects of the genre.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 217', 'DETECTIVE, MYSTERY LITERATURE', '36669', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 145', 'Nathaniel Rudavsky-Brody', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Origins, evolution, conventions, criticism, and theory of the detective and mystery story; history of the Gothic novel; later development of the tale of terror; major works of this type in Western fiction, drama, and film.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 256', 'LITERATURE AND OTHER ARTS: 1870-1950', '14484', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 337', 'Carlos Colmenares Gil', 1, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Interaction of the arts in the development of Western literature, painting, and music in movements such as Impressionism, Symbolism, Constructivism, Expressionism, Dada, and Surrealism.', ARRAY['IUB GenEd A&H credit
COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 301', 'SPECIAL TOPICS IN COMPARATIVE LITERATURE', '36545', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:10 PM', 'BH 145', 'Russell Valentino', 14, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Special topics concerning two or more literary traditions or literature and other areas in the humanities.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 315', 'LYRIC POETRY', '29853', 'Class Status', 'MW Monday, Wednesday 7:00 PM–9:30 PM', 'BH 229', 'Herbert Marks', 3, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Close reading of exemplary poems with an emphasis on interpretation and on the interplay between literal and figurative language. Topics will include the way poems are shaped, their ambiguous status as private and public statements, and their relation to tradition, to their readers, and to one another.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 317', 'EPIC: HEROES, GODS, AND REBELS', '35060', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 308', 'Jeffrey Johnson', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Historical and comparative survey of one or more traditions of epic poetry. Origins, evolution, conventions, criticism, and theory of the chosen tradition(s) to be studied through readings of selected epics. Some consideration of the social and political roles of individual epics and the genre.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit
COLL (CASE) Culture Studies: Global Civ & Culture'], NULL),
    ('CMLT-C 318', 'SATIRE', '34847', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'BH 240', 'Izabela Potapowicz', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Historical and analytical study of forms, techniques and scope of satire from antiquity to the internet. Consideration of the role of ridicule in defending or attacking institutions, values, and beliefs.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 322', 'WRITING AND PHOTOGRAPHY', '36645', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 208', 'Bill Johnston', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Examines the multiple connections between the literary and photographic arts. Considers thematic, aesthetic, and theoretical parallels and differences between the two worlds, including literary works in which photographs play a crucial role, and ways in which photography has been interpreted through the written word.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 345', 'LITERATURE AND RELIGION', '29412', 'Class Status', 'MW Monday, Wednesday 3:55 PM–6:25 PM', 'LH 135', 'Herbert Marks', 4, NULL, 'Lecture', '3', 'LINDLEY HALL', ARRAY[]::TEXT[], 'Literature from or about one or more religious traditions. Religious literature as influenced by-but distinct from-theology, religious doctrine, or philosophy. The impact of imaginative literature on the growth of religious ideas. Includes the study of historical contexts.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 349', 'LITERATURE AND SCIENCE', '13692', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'WH 009', 'Izabela Potapowicz', 17, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'The intersection of literature and the arts with science and technology, including the representation of scientific discovery and perspective, the dramatization of science''s impact on society, the image of the scientist as artist. May include literature by scientists, and the use of scientific methods of analysis for interpreting literature.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 364', 'THE CARIBBEAN: LITERATURE AND THEORY', '34044', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'BH 343', 'Carlos Colmenares Gil', 9, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Poetry, fiction, drama, musical, lyrics, travel literature, and prose from the Anglophone, Francophone, Hispanophone, and Dutch-speaking Caribbean. Discussion of major currents affecting literary production and interpretation. Topics such as immigration, diaspora, Rastafarianism, Voudoun, tourism.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 400', 'STUDIES IN COMPARATIVE LITERATURE', '34928', 'Class Status', 'TuTh Tuesday, Thursday 3:35 PM–4:50 PM', 'SY 137', 'Douglas Hofstadter', 4, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'Specific problems concerning the relationship of two or more literatures, or of literature and another area in the humanities.', ARRAY['COLL (CASE) A&H Breadth of Inquiry credit'], NULL),
    ('CMLT-C 499', 'STUDIES FOR HONORS', '1352', 'Class Status', NULL, NULL, 'Jacob Emery', 10, NULL, 'Readings', '2–6', NULL, ARRAY[]::TEXT[], 'Independent reading and research in conjunction with an advanced course in comparative literature or an honors paper or project.', ARRAY[]::TEXT[], NULL),
    ('CMLT-C 501', 'INTRODUCTION TO CONTEMPORARY LITERARY STUDIES', '1353', 'Class Status', 'M Monday 3:10 PM–5:40 PM', 'BH 106', 'Sonia Velazquez', 8, NULL, 'Seminar', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introduces major questions and ideas about the nature of literature and the principles and methods of its study.', ARRAY[]::TEXT[], NULL),
