    ('COGS-G 901', 'ADVANCED RESEARCH', '4316', 'Class Status', NULL, NULL, 'Tim Pleskac', 22, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 101', 'INTRODUCTION TO COGNITIVE SCIENCE', '5474', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–1:35 PM', 'SE 140', 'Andrew Goldman', 0, 'Lecture', 'Lecture', '3', 'SWAIN EAST', ARRAY[]::TEXT[], 'Introduction to the study of the human mind and intelligent systems using an integrative approach. Explores the nature of intelligence through simulations, robots, human experiments and philosophical inquiry. Topics include perception, consciousness, mental representations, models of cognition and brain anatomy as each relates to cognition. Provides an overview for those students considering a major in Cognitive Science or a related field.', ARRAY['IUB GenEd N&M credit
COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
