FOREST', 'READ AND WILLKIE PROGRAMS
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('COGS-Q 260', 'PROGRAMMING FOR THE COGNITIVE AND INFORMATION SCIENCES', '9063', 'Class Status', 'TuTh Tuesday, Thursday 4:30 PM–5:45 PM', 'GY 3060', 'Ruth Eberle', 8, 'Lecture', 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Students will learn to write simple computer programs. Programming assignments will focus on the implementation of an important class of models from cognitive science, such as neural networks or production systems.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 260', 'PROGRAMMING FOR THE COGNITIVE AND INFORMATION SCIENCES', '9064', 'Class Status', 'F Friday 3:00 PM–4:15 PM', 'BH 216', 'Ruth Eberle', 8, 'Laboratory', 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Students will learn to write simple computer programs. Programming assignments will focus on the implementation of an important class of models from cognitive science, such as neural networks or production systems.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 350', 'MATH AND LOGIC FOR COGNITIVE SCIENCE', '10590', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'GY 3060', 'Emma Alexandrov', 5, 'Lecture', 'Lecture', '4', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'An introduction to the suite of mathematical and logical tools used in the cognitive and information sciences, including finite mathematics, autotmata and computability theory, elementary probability, and statistics together with short introductions to formal semantics and dynamical systems.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('COGS-Q 350', 'MATH AND LOGIC FOR COGNITIVE SCIENCE', '10591', 'Class Status', 'F Friday 9:45 AM–11:00 AM', 'LH 125', 'Emma Alexandrov', 5, 'Laboratory', 'Lecture', '4', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'An introduction to the suite of mathematical and logical tools used in the cognitive and information sciences, including finite mathematics, autotmata and computability theory, elementary probability, and statistics together with short introductions to formal semantics and dynamical systems.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('COGS-Q 351', 'INTRODUCTION TO ARTIFICAL INTELLIGENCE AND COMPUTER SIMULATION', '1365', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'OP 105', 'Yijie Wang', 1, NULL, 'Lecture', '3', 'OPTOMETRY SCHOOL', ARRAY[]::TEXT[], 'A survey of techniques for machine intelligence and their relation to human intelligence. Topics include modeling techniques, neural networks and parallel processing systems, problem-solving methods, vision, heuristics, production systems, speech perception, and natural language understanding.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit'], NULL),
    ('COGS-Q 370', 'EXPERIMNTS & MODELS IN COGNITN', '8903', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'PY 120A', 'Robert Goldstone', 0, 'Lecture', 'Lecture', '4', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'This course develops tools for studying mind and intelligence, including experimental techniques, and mathematical and computational models of human behavior. Topics include neural structures for cognition, attention, perception, memory, problem solving, judgment, decision making, and consciousness. Students will design and analyze laboratory experiments and apply formal models to the results. Credit given for only one of COGS Q370 or Q270.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('COGS-Q 370', 'EXPERIMNTS & MODELS IN COGNITN', '8907', 'Closed', 'W Wednesday 1:50 PM–2:40 PM', 'LH 030', 'Robert Goldstone', 0, 'Laboratory', 'Lecture', '4', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'This course develops tools for studying mind and intelligence, including experimental techniques, and mathematical and computational models of human behavior. Topics include neural structures for cognition, attention, perception, memory, problem solving, judgment, decision making, and consciousness. Students will design and analyze laboratory experiments and apply formal models to the results. Credit given for only one of COGS Q370 or Q270.', ARRAY['COLL (CASE) N&M Breadth of Inquiry credit
COLL INTENSIVE WRITING SECTIONS'], NULL),
    ('COGS-Q 450', 'TOPICS IN COGNITIVE & INFO SCI', '14998', 'Class Status', 'TuTh Tuesday, Thursday 3:35 PM–4:50 PM', 'SY 137', 'Douglas Hofstadter', 4, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course covers in depth special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 499', 'HONORS RESEARCH PROJECT IN THE COGNITIVE AND INFORMATION SCIENCES', '1370', 'Class Status', NULL, NULL, 'Erica Cartmill', 5, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], 'Methods of research in cognitive science are analyzed. Students present their projects for discussion and analysis.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 510', 'SEMINAR ON PROFESSIONAL DEVELOPMENT FOR COGNITIVE SCIENTISTS', '4832', 'Closed', 'W Wednesday 1:30 PM–4:00 PM', 'PY 128', 'Karin James', 0, NULL, 'Lecture', '2', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Discussions in this course cover a wide range of issues facing academic cognitive scientists, including: the ethical conduct of research, grant proposal writing and review, critical reading of the scientific literature, scientific writing, presentation skills, applying for jobs, teaching, challenges facing underrepresented groups in science, and issues in cross-disciplinary collaboration.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 560', 'EXPERIMENTAL METHODS IN COGNITIVE SCIENCE', '29350', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'PY 228', 'Tim Pleskac', 3, NULL, 'Lecture', '3', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'The specific goals of this course are: a) an understanding of experimental design and the resources for future studies; b) an understanding of converging measures and programmatic research; c) discussion of current controversies in experimental design; and d) hands on experience designing, conducting, and critiquing experiments.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 590', 'TOPICS IN THE COGNITIVE AND INFORMATION SCIENCES', '14999', 'Class Status', 'TuTh Tuesday, Thursday 3:35 PM–4:50 PM', 'SY 137', 'Douglas Hofstadter', 4, NULL, 'Lecture', '3', 'SYCAMORE HALL', ARRAY[]::TEXT[], 'This course covers in depth special topics not ordinarily covered in other departmental courses. Topics vary with instructor and semester.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 700', 'SEMINAR IN COGNITIVE SCIENCE', '29341', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'GY 3060', 'Randall Beer', 7, NULL, 'Lecture', '3', 'GEOLOGICAL SCIENCES', ARRAY[]::TEXT[], 'Intensive study of specific topics in Cognitive Science. Topics and instructors will change regularly.', ARRAY[]::TEXT[], NULL),
    ('COGS-Q 733', 'COLLOQUIUM SERIES', '1371', 'Class Status', 'M Monday 3:55 PM–5:15 PM', 'PY 101', 'Bonnie Nozari', 35, NULL, 'Activity', '1', 'PSYCHOLOGY', ARRAY[]::TEXT[], 'Four semesters of this course are required. The class will meet every week. At some meetings, invited speakers will present colloquia. At the remaining meetings students will present their own work, or read and discuss contemporary cognitive science research.', ARRAY[]::TEXT[], NULL),
