    ('COGS-X 373', 'INTERNSHIP IN PROFESSIONAL PRACTICE', '1368', 'Class Status', NULL, NULL, 'Erica Cartmill', 10, NULL, 'Practice', '1–6', NULL, ARRAY[]::TEXT[], 'Professional work experience in an industry or research organization setting, using skills/knowledge acquired in cognitive science coursework. Requires learning contract. Evaluation by site supervisor and Cognitive Science Program.', ARRAY[]::TEXT[], NULL),
