    ('COLL-G 123', 'SUCCESS AT IU AND BEYOND FOR GROUPS SCHOLARS', '5020', 'Class Status', 'Tu Tuesday 5:30 PM–6:20 PM', 'BH 227', 'Kathy Essex', 34, NULL, 'Seminar', '1', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'For Groups students only. Acquisition of leadership, study, and time-management skills needed for success in university-level course work. May also focus on skills and knowledge required for success in preparing for a particular profession.', ARRAY[]::TEXT[], NULL),
    ('COLL-G 133', 'GROUPS FIRST-YEAR SEMINAR I', '6769', 'Class Status', 'F Friday 11:35 AM–12:25 PM', 'MU 110', 'Samuel Young, Kim Jenkins', 92, NULL, 'Lecture', '1', 'MERRILL HALL', ARRAY[]::TEXT[], 'For freshman-level Groups students only. Develops the essential life skills necessary to successfully transition into university life and navigate the college experience. Examines the areas of academic wellness, financial literacy, career development, social media use, mental health, and campus resource utilization. Groups Scholars learn practical skills through the completion of assignments tailored to degree-mapping, articulating professional experiences, and personal reflection.', ARRAY['Class uses IU eTexts'], NULL),
    ('COLL-P 155', 'PUBLIC ORAL COMMUNICATION', '10596', 'Class Status', 'MF Monday, Friday 8:00 AM–8:50 AM', 'BH 236', 'Margaret Gardiner', 1, 'Laboratory', 'Laboratory', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Prepares students in the liberal arts to communicate effectively with public audiences. Emphasizes oral communication as practiced in public contexts: how to advance reasoned claims in public; how to adapt public oral presentations to particular audiences; how to listen to, interpret, and evaluate public discourse; and how to formulate a clear response.', ARRAY['Class uses IU eTexts'], NULL),
